def gen(rng, size):
    n = max(1, min(size, 9))

    def rand_original(k):
        return ''.join(rng.choice('abcde') for _ in range(k))

    def encode(orig):
        length = len(orig)
        if length > 1:
            k = rng.randint(0, min(length - 1, 4))
            cuts = sorted(rng.sample(range(1, length), k))
        else:
            cuts = []
        pieces = []
        prev = 0
        for c in cuts:
            pieces.append(orig[prev:c])
            prev = c
        pieces.append(orig[prev:])
        out = []
        digit_run = 0
        for p in pieces:
            token = str(len(p))
            if rng.random() < 0.5 and digit_run + len(token) <= 3:
                out.append(token)
                digit_run += len(token)
            else:
                out.append(p)
                digit_run = 0
        return ''.join(out)

    orig = rand_original(n)
    s1 = encode(orig)
    if rng.random() < 0.5:
        s2 = encode(orig)
    else:
        s2 = encode(rand_original(n))
    return [s1, s2]

