class Solution:
    def possiblyEquals(self, s1, s2):
        n1, n2 = len(s1), len(s2)

        def successors(i, j, diff):
            res = []
            if diff == 0:
                if i == n1 or j == n2:
                    return res
                d1 = s1[i].isdigit()
                d2 = s2[j].isdigit()
                if d1:
                    num = 0
                    k = i
                    while k < n1 and k < i + 3 and s1[k].isdigit():
                        num = num * 10 + int(s1[k])
                        k += 1
                        res.append((k, j, num))
                if d2:
                    num = 0
                    k = j
                    while k < n2 and k < j + 3 and s2[k].isdigit():
                        num = num * 10 + int(s2[k])
                        k += 1
                        res.append((i, k, -num))
                if not d1 and not d2 and s1[i] == s2[j]:
                    res.append((i + 1, j + 1, 0))
            elif diff > 0:
                if j == n2:
                    return res
                if s2[j].isdigit():
                    num = 0
                    k = j
                    while k < n2 and k < j + 3 and s2[k].isdigit():
                        num = num * 10 + int(s2[k])
                        k += 1
                        res.append((i, k, diff - num))
                else:
                    res.append((i, j + 1, diff - 1))
            else:
                if i == n1:
                    return res
                if s1[i].isdigit():
                    num = 0
                    k = i
                    while k < n1 and k < i + 3 and s1[k].isdigit():
                        num = num * 10 + int(s1[k])
                        k += 1
                        res.append((k, j, diff + num))
                else:
                    res.append((i + 1, j, diff + 1))
            return res

        start = (0, 0, 0)
        target = (n1, n2, 0)
        if start == target:
            return True
        seen = {start}
        stack = [start]
        while stack:
            state = stack.pop()
            for nxt in successors(*state):
                if nxt == target:
                    return True
                if nxt not in seen:
                    seen.add(nxt)
                    stack.append(nxt)
        return False

