from functools import lru_cache


class Solution:
    def possiblyEquals(self, s1, s2):
        n1, n2 = len(s1), len(s2)

        @lru_cache(maxsize=None)
        def match(i, j, diff):
            if i == n1 and j == n2:
                return diff == 0
            if diff == 0:
                if i == n1 or j == n2:
                    return False
                c1, c2 = s1[i], s2[j]
                d1, d2 = c1.isdigit(), c2.isdigit()
                if d1:
                    num = 0
                    k = i
                    while k < n1 and k < i + 3 and s1[k].isdigit():
                        num = num * 10 + int(s1[k])
                        k += 1
                        if match(k, j, num):
                            return True
                if d2:
                    num = 0
                    k = j
                    while k < n2 and k < j + 3 and s2[k].isdigit():
                        num = num * 10 + int(s2[k])
                        k += 1
                        if match(i, k, -num):
                            return True
                if not d1 and not d2 and c1 == c2:
                    return match(i + 1, j + 1, 0)
                return False
            elif diff > 0:
                if j == n2:
                    return False
                if s2[j].isdigit():
                    num = 0
                    k = j
                    while k < n2 and k < j + 3 and s2[k].isdigit():
                        num = num * 10 + int(s2[k])
                        k += 1
                        if match(i, k, diff - num):
                            return True
                    return False
                return match(i, j + 1, diff - 1)
            else:
                if i == n1:
                    return False
                if s1[i].isdigit():
                    num = 0
                    k = i
                    while k < n1 and k < i + 3 and s1[k].isdigit():
                        num = num * 10 + int(s1[k])
                        k += 1
                        if match(k, j, diff + num):
                            return True
                    return False
                return match(i + 1, j, diff + 1)

        return match(0, 0, 0)

