var possiblyEquals = function(s1, s2) {
    const n1 = s1.length, n2 = s2.length;
    const memo = new Map();

    function isDigit(ch) {
        return ch >= '0' && ch <= '9';
    }

    function match(i, j, diff) {
        const key = i + ',' + j + ',' + diff;
        if (memo.has(key)) return memo.get(key);
        let result;
        if (i === n1 && j === n2) {
            result = diff === 0;
        } else if (diff === 0) {
            if (i === n1 || j === n2) {
                result = false;
            } else {
                const c1 = s1[i], c2 = s2[j];
                const d1 = isDigit(c1), d2 = isDigit(c2);
                result = false;
                if (d1) {
                    let num = 0, k = i;
                    while (k < n1 && k < i + 3 && isDigit(s1[k])) {
                        num = num * 10 + (s1.charCodeAt(k) - 48);
                        k++;
                        if (match(k, j, num)) { result = true; break; }
                    }
                }
                if (!result && d2) {
                    let num = 0, k = j;
                    while (k < n2 && k < j + 3 && isDigit(s2[k])) {
                        num = num * 10 + (s2.charCodeAt(k) - 48);
                        k++;
                        if (match(i, k, -num)) { result = true; break; }
                    }
                }
                if (!result && !d1 && !d2 && c1 === c2) {
                    result = match(i + 1, j + 1, 0);
                }
            }
        } else if (diff > 0) {
            if (j === n2) {
                result = false;
            } else if (isDigit(s2[j])) {
                result = false;
                let num = 0, k = j;
                while (k < n2 && k < j + 3 && isDigit(s2[k])) {
                    num = num * 10 + (s2.charCodeAt(k) - 48);
                    k++;
                    if (match(i, k, diff - num)) { result = true; break; }
                }
            } else {
                result = match(i, j + 1, diff - 1);
            }
        } else {
            if (i === n1) {
                result = false;
            } else if (isDigit(s1[i])) {
                result = false;
                let num = 0, k = i;
                while (k < n1 && k < i + 3 && isDigit(s1[k])) {
                    num = num * 10 + (s1.charCodeAt(k) - 48);
                    k++;
                    if (match(k, j, diff + num)) { result = true; break; }
                }
            } else {
                result = match(i + 1, j, diff + 1);
            }
        }
        memo.set(key, result);
        return result;
    }

    return match(0, 0, 0);
};
